import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";var i=JSON.parse(`{"title":"Major Courses","description":"Introduces SCUT's schools and majors, with links to major-specific study guides","frontmatter":{"lang":"en-US","title":"Major Courses","description":"Introduces SCUT's schools and majors, with links to major-specific study guides","llm_translated":true},"headers":[],"relativePath":"en/learn/curricular/majors.md","filePath":"en/learn/curricular/majors.md","lastUpdated":1784829332000}`),a={name:`en/learn/curricular/majors.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /en/learn/curricular/majors.md for this page in Markdown format</div><h1 id="major-courses" tabindex="-1">Major Courses <a class="header-anchor" href="#major-courses" aria-label="Permalink to “Major Courses”">​</a></h1><p>An introduction to the schools and majors at SCUT, along with links to major-specific study guides (for reference only).</p><p>TODO: Add study guides and open-source resource links for the following major schools:</p><ul class="contains-task-list"><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> School of Mechanical &amp; Automotive Engineering / School of Civil Engineering &amp; Transportation</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> School of Electronic &amp; Information Engineering / School of Automation Science &amp; Engineering</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> School of Architecture / School of Business Administration / School of Economics &amp; Finance</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> School of Chemistry &amp; Chemical Engineering / School of Light Industry &amp; Engineering</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> School of Software Engineering / School of Computer Science &amp; Engineering</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> School of Materials Science &amp; Engineering / School of Environment &amp; Energy</li></ul><h2 id="school-of-future-technology" tabindex="-1">School of Future Technology <a class="header-anchor" href="#school-of-future-technology" aria-label="Permalink to “School of Future Technology”">​</a></h2><h3 id="school-of-future-technology-course-guide" tabindex="-1">School of Future Technology Course Guide <a class="header-anchor" href="#school-of-future-technology-course-guide" aria-label="Permalink to “School of Future Technology Course Guide”">​</a></h3><p>Upperclassmen from the School of Future Technology (SCUT School of Future Technology AI Association) and other contributors created this repository to share and exchange course-related resources.</p><p><a href="https://openfutech.github.io/SCUT-FT-Guide/" target="_blank" rel="noreferrer">SCUT Future Technology Course Guide - Web Link</a></p><p><a href="https://github.com/OpenFuTech/SCUT-FT-Guide/" target="_blank" rel="noreferrer">GitHub Repository Link</a></p><p>(Access may be limited from domestic/campus networks.)</p><h3 id="scut-cs-ai-research入门-guide" tabindex="-1">SCUT CS/AI Research入门 Guide <a class="header-anchor" href="#scut-cs-ai-research入门-guide" aria-label="Permalink to “SCUT CS/AI Research入门 Guide”">​</a></h3><p>Given the drawback that SCUT&#39;s AI and Computer Science training plans offer little to improve research capabilities, <a href="https://github.com/oplisty" target="_blank" rel="noreferrer">Oplisty</a>, together with several classmates from CS and AI programs, created this website to help junior students get started in research and avoid unnecessary detours.</p><p><a href="https://github.com/oplisty/SCUT-AIdiy" target="_blank" rel="noreferrer">GitHub Repository Link</a></p><p><a href="https://lin-ze-pengsorganization.gitbook.io/aidiy/" target="_blank" rel="noreferrer">Website Link</a></p><h3 id="scuteee-scut-electrical-and-electronics-engineering-knowledge-base" tabindex="-1">SCUTEEE - SCUT Electrical and Electronics Engineering Knowledge Base <a class="header-anchor" href="#scuteee-scut-electrical-and-electronics-engineering-knowledge-base" aria-label="Permalink to “SCUTEEE - SCUT Electrical and Electronics Engineering Knowledge Base”">​</a></h3><p>SCUTEEE is like IEEE. SCUT stands for South China University of Technology, and EEE stands for Electrical and Electronics Engineers. SCUTEEE focuses on similar areas as IEEE: electrical engineering, electronics, microelectronics, computer science, automation, and related fields. These areas have significant overlap, with many shared courses that can provide mutual reference.</p><p><a href="https://github.com/scuteee/scuteee" target="_blank" rel="noreferrer">GitHub Repository Link</a></p><p><a href="https://scuteee.com/" target="_blank" rel="noreferrer">Website Link</a></p>`,19)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};